import { useNavigate } from "react-router-dom";

export default function Navbar() {
  const nav = useNavigate();

  const logout = () => {
    localStorage.clear();
    nav("/");
  };

  return (
    <div style={styles.navbar}>

      <div style={styles.logo}>
        DailyWorker
      </div>

      <div style={styles.links}>
        <button style={styles.linkBtn} onClick={() => nav("/")}>
          Home
        </button>

        <button style={styles.linkBtn} onClick={() => nav("/customer")}>
          Customer
        </button>

        <button style={styles.linkBtn} onClick={() => nav("/labour")}>
          Labour
        </button>

        <button style={styles.logoutBtn} onClick={logout}>
          Logout
        </button>
      </div>

    </div>
  );
}

const styles = {
  navbar: {
    height: "70px",
    background: "white",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 40px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.08)",
    position: "sticky",
    top: 0,
    zIndex: 100
  },

  logo: {
    fontSize: "24px",
    fontWeight: "bold",
    color: "#2563eb"
  },

  links: {
    display: "flex",
    gap: "15px",
    alignItems: "center"
  },

  linkBtn: {
    border: "none",
    background: "transparent",
    fontSize: "15px",
    cursor: "pointer",
    color: "#333"
  },

  logoutBtn: {
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "10px 18px",
    borderRadius: "8px",
    cursor: "pointer"
  }
};
